<?php
namespace App\Domain\Loot;use App\Domain\Loot\Data\LootDrop;use App\Domain\Loot\Data\LootResult;use App\Domain\Random\RandomNumberGenerator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Monster;use App\Models\MonsterLootEntry;use InvalidArgumentException;
final class LootGenerator {private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function generateFor(Monster $monster):LootResult{if($monster->status!==CatalogStatus::ACTIVE)throw new InvalidArgumentException('Monster must be active.');$entries=MonsterLootEntry::where('monster_id',$monster->id)->where('status',CatalogStatus::ACTIVE)->whereHas('item',function($q){$q->where('status',CatalogStatus::ACTIVE);})->with('item')->orderBy('sort_order')->orderBy('id')->get();$drops=[];foreach($entries as $e){$roll=$this->rng->randomInt(1,10000);if($roll>$e->drop_chance_basis_points)continue;$quantity=$e->minimum_quantity===$e->maximum_quantity?$e->minimum_quantity:$this->rng->randomInt($e->minimum_quantity,$e->maximum_quantity);$i=$e->item;$drops[]=new LootDrop($i->id,$i->code,$i->name,$i->item_type,$i->rarity,$quantity,$e->drop_chance_basis_points,$roll);}return new LootResult($monster->id,$monster->code,$monster->name,$drops);}}
